ALGORITHM Diffie-Hellman-Key-Exchange
INPUT: None (public parameters agreed beforehand)
OUTPUT: Shared secret S shared between Alice and Bob

// ============================================
// PUBLIC PARAMETERS (agreed by both parties)
// ============================================
CONSTANTS:
  p = large prime number
  g = generator (primitive root of p)

// ============================================
// PHASE 1: KEY GENERATION
// ============================================

// Alice's Key Generation
FUNCTION Alice-Generate-Keys():
  a = RANDOM-LARGE-INTEGER()  // Alice's private key
  A = MODEXP(g, a, p)          // Alice's public key: g^a mod p
  RETURN (a, A)

// Bob's Key Generation
FUNCTION Bob-Generate-Keys():
  b = RANDOM-LARGE-INTEGER()  // Bob's private key
  B = MODEXP(g, b, p)          // Bob's public key: g^b mod p
  RETURN (b, B)

// ============================================
// PHASE 2: KEY EXCHANGE
// ============================================

// Alice sends A to Bob
// Bob receives A from Alice
// Bob sends B to Alice
// Alice receives B from Bob

// ============================================
// PHASE 3: SHARED SECRET COMPUTATION
// ============================================

// Alice computes shared secret
FUNCTION Alice-Compute-Secret(B, a, p):
  S = MODEXP(B, a, p)  // S = (g^b)^a mod p = g^(ab) mod p
  RETURN S

// Bob computes shared secret
FUNCTION Bob-Compute-Secret(A, b, p):
  S = MODEXP(A, b, p)  // S = (g^a)^b mod p = g^(ab) mod p
  RETURN S

// ============================================
// MAIN PROTOCOL EXECUTION
// ============================================
BEGIN
  // Public parameters p and g are already shared

  // Alice generates her key pair
  (a, A) = Alice-Generate-Keys()

  // Bob generates his key pair
  (b, B) = Bob-Generate-Keys()

  // Exchange public keys (insecure channel)
  Alice-receives B from Bob
  Bob-receives A from Alice

  // Both compute the same shared secret
  S_alice = Alice-Compute-Secret(B, a, p)
  S_bob = Bob-Compute-Secret(A, b, p)

  // Verification: S_alice should equal S_bob
  IF S_alice == S_bob THEN
    RETURN "Key exchange successful! Shared secret: " + S_alice
  ELSE
    RETURN "Key exchange failed!"
  END IF
END

#include <stdio.h>
#include <stdlib.h>
#include <time.h>

/*
 * Diffie-Hellman Key Exchange Implementation in C
 * Demonstrates the classic DHKE protocol between Alice and Bob
 */

// Structure to hold key pair
typedef struct {
    long long private_key;
    long long public_key;
} KeyPair;

// Modular exponentiation: computes (base^exp) mod mod
// Uses square-and-multiply algorithm for efficiency
long long mod_pow(long long base, long long exp, long long mod) {
    long long result = 1;
    base = base % mod;

    while (exp > 0) {
        // If exp is odd, multiply result with base
        if (exp % 2 == 1) {
            result = (result * base) % mod;
        }
        // exp must be even now
        exp = exp / 2;
        base = (base * base) % mod;
    }
    return result;
}

// Generate a random private key (simplified for demonstration)
long long generate_private_key(long long max) {
    srand(time(NULL));
    return (rand() % (max - 2)) + 2;  // Random between 2 and max-1
}

// Generate public key from private key
long long generate_public_key(long long private_key, long long g, long long p) {
    return mod_pow(g, private_key, p);
}

// Compute shared secret
long long compute_shared_secret(long long others_public, long long private_key, long long p) {
    return mod_pow(others_public, private_key, p);
}

// Demonstrate Diffie-Hellman Key Exchange
void demonstrate_dhke() {
    // Public parameters (small values for demonstration)
    long long p = 23;  // Prime modulus
    long long g = 5;   // Generator

    printf("========================================\n");
    printf("  Diffie-Hellman Key Exchange in C\n");
    printf("========================================\n\n");

    printf("Public Parameters:\n");
    printf("  Prime (p) = %lld\n", p);
    printf("  Generator (g) = %lld\n\n", g);

    // Alice's key generation
    long long a = 6;  // Alice's private key
    long long A = generate_public_key(a, g, p);

    printf("[ALICE]\n");
    printf("  Private key (a): %lld\n", a);
    printf("  Public key (A = g^a mod p): %lld\n\n", A);

    // Bob's key generation
    long long b = 15;  // Bob's private key
    long long B = generate_public_key(b, g, p);

    printf("[BOB]\n");
    printf("  Private key (b): %lld\n", b);
    printf("  Public key (B = g^b mod p): %lld\n\n", B);

    // Key exchange (insecure channel)
    printf("[KEY EXCHANGE]\n");
    printf("  Alice sends A = %lld to Bob\n", A);
    printf("  Bob sends B = %lld to Alice\n\n", B);

    // Shared secret computation
    long long alice_secret = compute_shared_secret(B, a, p);
    long long bob_secret = compute_shared_secret(A, b, p);

    printf("[SHARED SECRET COMPUTATION]\n");
    printf("  Alice computes: S = B^a mod p = %lld^%lld mod %lld = %lld\n", 
           B, a, p, alice_secret);
    printf("  Bob computes:   S = A^b mod p = %lld^%lld mod %lld = %lld\n\n", 
           A, b, p, bob_secret);

    // Verification
    printf("[RESULT]\n");
    if (alice_secret == bob_secret) {
        printf("  SUCCESS! Both parties share the secret: %lld\n", alice_secret);
    } else {
        printf("  ERROR: Secrets do not match!\n");
    }
}

// Demonstrate Station-to-Station Protocol concept
void demonstrate_sts_concept() {
    printf("\n========================================\n");
    printf("  Station-to-Station (STS) Protocol\n");
    printf("========================================\n\n");

    printf("STS Protocol Steps (for reference):\n\n");
    printf("1. Alice and Bob exchange DH public keys\n");
    printf("   - Alice -> Bob: g^a mod p\n");
    printf("   - Bob -> Alice: g^b mod p\n\n");

    printf("2. Both compute shared secret: g^(ab) mod p\n\n");

    printf("3. Derive session key using KDF: K = KDF(g^(ab) mod p)\n\n");

    printf("4. Mutual Authentication with Digital Signatures:\n");
    printf("   - Alice signs: Sig_A(g^a, g^b)\n");
    printf("   - Bob signs:   Sig_B(g^b, g^a)\n\n");

    printf("5. Encrypt signatures with session key:\n");
    printf("   - Alice -> Bob: E_K(Sig_A(g^a, g^b))\n");
    printf("   - Bob -> Alice: E_K(Sig_B(g^b, g^a))\n\n");

    printf("Security: MITM attack prevented because:\n");
    printf("   - Only legitimate parties can sign with their private keys\n");
    printf("   - Signatures require the correct shared secret\n");
    printf("   - Public verification keys authenticate the parties\n");
}

int main() {
    demonstrate_dhke();
    demonstrate_sts_concept();
    return 0;
}

import java.math.BigInteger;
import java.security.MessageDigest;
import java.security.SecureRandom;

/**
 * Diffie-Hellman Key Exchange Implementation in Java
 * Includes simulation of the STS (Station-to-Station) protocol concept
 */
public class DiffieHellmanKeyExchange {

    private BigInteger privateKey;
    private BigInteger publicKey;
    private BigInteger sharedSecret;
    private final BigInteger p;  // Prime modulus
    private final BigInteger g;  // Generator

    /**
     * Initialize with public parameters
     */
    public DiffieHellmanKeyExchange(BigInteger p, BigInteger g) {
        this.p = p;
        this.g = g;
    }

    /**
     * Generate key pair for this party
     */
    public void generateKeyPair() {
        // Generate random private key (size of p minus 1 bit)
        SecureRandom random = new SecureRandom();
        privateKey = new BigInteger(p.bitLength() - 1, random);

        // Compute public key: g^a mod p
        publicKey = g.modPow(privateKey, p);
    }

    /**
     * Compute shared secret using other party's public key
     */
    public void computeSharedSecret(BigInteger othersPublicKey) {
        // S = (othersPublicKey)^privateKey mod p
        sharedSecret = othersPublicKey.modPow(privateKey, p);
    }

    // Getters
    public BigInteger getPublicKey() { return publicKey; }
    public BigInteger getPrivateKey() { return privateKey; }
    public BigInteger getSharedSecret() { return sharedSecret; }
    public BigInteger getP() { return p; }
    public BigInteger getG() { return g; }

    /**
     * Simple Key Derivation Function (KDF) - simplified version
     * In practice, use HKDF or similar
     */
    public static byte[] deriveKey(BigInteger sharedSecret, int keyLength) throws Exception {
        MessageDigest sha256 = MessageDigest.getInstance("SHA-256");
        byte[] hash = sha256.digest(sharedSecret.toByteArray());

        // Truncate or expand to desired key length
        byte[] key = new byte[keyLength];
        System.arraycopy(hash, 0, key, 0, Math.min(hash.length, keyLength));
        return key;
    }

    /**
     * Demonstrate the complete key exchange protocol
     */
    public static void main(String[] args) throws Exception {
        System.out.println("========================================");
        System.out.println("  Diffie-Hellman Key Exchange - Java");
        System.out.println("========================================\n");

        // Using small values for demonstration
        BigInteger p = new BigInteger("23");
        BigInteger g = new BigInteger("5");

        System.out.println("Public Parameters:");
        System.out.println("  Prime (p): " + p);
        System.out.println("  Generator (g): " + g + "\n");

        // Alice's setup
        DiffieHellmanKeyExchange alice = new DiffieHellmanKeyExchange(p, g);
        alice.generateKeyPair();

        System.out.println("[ALICE]");
        System.out.println("  Private key: " + alice.getPrivateKey());
        System.out.println("  Public key: " + alice.getPublicKey());

        // Bob's setup
        DiffieHellmanKeyExchange bob = new DiffieHellmanKeyExchange(p, g);
        bob.generateKeyPair();

        System.out.println("\n[BOB]");
        System.out.println("  Private key: " + bob.getPrivateKey());
        System.out.println("  Public key: " + bob.getPublicKey());

        // Key exchange - both compute shared secret
        alice.computeSharedSecret(bob.getPublicKey());
        bob.computeSharedSecret(alice.getPublicKey());

        System.out.println("\n[KEY EXCHANGE COMPLETE]");
        System.out.println("  Alice's shared secret: " + alice.getSharedSecret());
        System.out.println("  Bob's shared secret: " + bob.getSharedSecret());

        // Verify they match
        if (alice.getSharedSecret().equals(bob.getSharedSecret())) {
            System.out.println("  SUCCESS: Keys match!\n");
        }

        // Derive symmetric key using KDF
        byte[] aliceKey = deriveKey(alice.getSharedSecret(), 16);
        byte[] bobKey = deriveKey(bob.getSharedSecret(), 16);

        System.out.println("[KEY DERIVATION]");
        System.out.print("  Alice's derived key: ");
        printHex(aliceKey);
        System.out.print("  Bob's derived key:   ");
        printHex(bobKey);

        // Demonstrate STS Protocol concept
        demonstrateSTS();
    }

    /**
     * Print byte array as hex
     */
    private static void printHex(byte[] bytes) {
        StringBuilder sb = new StringBuilder();
        for (byte b : bytes) {
            sb.append(String.format("%02x", b));
        }
        System.out.println(sb.toString());
    }

    /**
     * Demonstrate STS (Station-to-Station) Protocol
     */
    private static void demonstrateSTS() {
        System.out.println("\n========================================");
        System.out.println("  Station-to-Station (STS) Protocol");
        System.out.println("========================================\n");

        System.out.println("STS Protocol - Authenticated Key Exchange:\n");

        System.out.println("Step 1: Same as basic DHKE");
        System.out.println("  - Alice and Bob exchange public keys (g^a, g^b)\n");

        System.out.println("Step 2: Compute shared secret");
        System.out.println("  - Both compute g^(ab) mod p\n");

        System.out.println("Step 3: Key Derivation");
        System.out.println("  - Derive session key K = KDF(g^(ab))\n");

        System.out.println("Step 4: Mutual Authentication");
        System.out.println("  - Alice signs: Sign_A(g^a || g^b)\n");
        System.out.println("  - Bob signs:   Sign_B(g^b || g^a)\n");

        System.out.println("Step 5: Exchange encrypted signatures");
        System.out.println("  - Alice -> Bob: E_K(Sign_A)\n");
        System.out.println("  - Bob -> Alice: E_K(Sign_B)\n");

        System.out.println("Security Properties:");
        System.out.println("  ✓ Mutual authentication prevents MITM");
        System.out.println("  ✓ Perfect Forward Secrecy maintained");
        System.out.println("  ✓ Used in TLS with certificates\n");
    }
}
